package org.example.aop.aspectj
import com.intellij.codeInsight.completion.CompletionContributor import com.intellij.codeInsight.completion.CompletionParameters import com.intellij.codeInsight.completion.CompletionProvider import com.intellij.codeInsight.completion.CompletionResultSet import com.intellij.codeInsight.completion.CompletionType import com.intellij.codeInsight.completion.PrioritizedLookupElement import com.intellij.codeInsight.lookup.LookupElementBuilder import com.intellij.patterns.PlatformPatterns import com.intellij.util.ProcessingContext import org.example.aop.inspection.AopInspectionRules
class AspectJCompletionContributor : CompletionContributor() { init { extend( CompletionType.BASIC, PlatformPatterns.psiElement().withLanguage(AspectJLanguage), AspectJPointcutCompletionProvider() ) } }
private class AspectJPointcutCompletionProvider : CompletionProvider<CompletionParameters>() { override fun addCompletions( parameters: CompletionParameters, context: ProcessingContext, result: CompletionResultSet ) { val fileText = parameters.position.containingFile.text val offset = parameters.offset if (!AspectJTextSupport.isPointcutContext(fileText, offset)) return
val prefix = AspectJTextSupport.extractCompletionPrefix(fileText, offset) val prefixed = result.withPrefixMatcher(prefix)
AopInspectionRules.pointcutCompletionItems.forEach { (designator, description) -> val element = LookupElementBuilder.create(designator) .withPresentableText("$designator(...)") .withTailText(" $description", true) .withTypeText("AspectJ pointcut") .withInsertHandler { ctx, _ -> ctx.document.insertString(ctx.tailOffset, "()") ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1) } prefixed.addElement(PrioritizedLookupElement.withPriority(element, 200.0)) }
AspectJTextSupport.collectDeclaredPointcutNames(fileText).forEach { pointcutName -> val element = LookupElementBuilder.create(pointcutName) .withPresentableText("$pointcutName()") .withTailText(" declared pointcut", true) .withTypeText("AspectJ") .withInsertHandler { ctx, _ -> ctx.document.insertString(ctx.tailOffset, "()") ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1) } prefixed.addElement(PrioritizedLookupElement.withPriority(element, 180.0)) }
listOf("&&", "||", "!").forEach { operator -> val element = LookupElementBuilder.create(operator) .withTailText(" logical operator", true) .withTypeText("AspectJ") prefixed.addElement(PrioritizedLookupElement.withPriority(element, 120.0)) } } }

package org.example.aop.aspectj

import com.intellij.codeInsight.completion.CompletionContributor
import com.intellij.codeInsight.completion.CompletionParameters
import com.intellij.codeInsight.completion.CompletionProvider
import com.intellij.codeInsight.completion.CompletionResultSet
import com.intellij.codeInsight.completion.CompletionType
import com.intellij.codeInsight.completion.PrioritizedLookupElement
import com.intellij.codeInsight.lookup.LookupElementBuilder
import com.intellij.patterns.PlatformPatterns
import com.intellij.psi.PsiElement
import com.intellij.util.ProcessingContext
import org.example.aop.inspection.AopInspectionRules
import org.example.aop.aspectj.psi.AspectDeclaration
import org.example.aop.aspectj.psi.PointcutDeclaration

class AspectJCompletionContributor : CompletionContributor() {
    init {
        extend(
            CompletionType.BASIC,
            PlatformPatterns.psiElement().withLanguage(AspectJLanguage),
            AspectJPointcutCompletionProvider()
        )
    }
}

private class AspectJPointcutCompletionProvider : CompletionProvider<CompletionParameters>() {
    override fun addCompletions(
        parameters: CompletionParameters,
        context: ProcessingContext,
        result: CompletionResultSet
    ) {
        val position = parameters.position
        val fileText = parameters.position.containingFile.text
        val offset = parameters.offset

        // Check if we're in a pointcut context (advice or pointcut declaration)
        if (!AspectJTextSupport.isPointcutContext(fileText, offset)) return

        val prefix = AspectJTextSupport.extractCompletionPrefix(fileText, offset)
        val prefixed = result.withPrefixMatcher(prefix)

        // Add built-in pointcut designators
        AopInspectionRules.pointcutCompletionItems.forEach { (designator, description) ->
            val element = LookupElementBuilder.create(designator)
                .withPresentableText("$designator(...)")
                .withTailText("  $description", true)
                .withTypeText("AspectJ pointcut")
                .withInsertHandler { ctx, _ ->
                    ctx.document.insertString(ctx.tailOffset, "()")
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                }
            prefixed.addElement(PrioritizedLookupElement.withPriority(element, 200.0))
        }

        // Collect declared pointcuts from PSI tree
        val declaredPointcuts = collectDeclaredPointcuts(parameters.position)
        declaredPointcuts.forEach { (pointcutName, pointcutDecl) ->
            val element = LookupElementBuilder.create(pointcutName)
                .withPresentableText("$pointcutName()")
                .withTailText("  declared pointcut", true)
                .withTypeText("AspectJ")
                .withInsertHandler { ctx, _ ->
                    ctx.document.insertString(ctx.tailOffset, "()")
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                }
            prefixed.addElement(PrioritizedLookupElement.withPriority(element, 180.0))
        }

        // Also keep regex-based fallback for compatibility
        AspectJTextSupport.collectDeclaredPointcutNames(fileText).forEach { pointcutName ->
            val element = LookupElementBuilder.create(pointcutName)
                .withPresentableText("$pointcutName()")
                .withTailText("  declared pointcut (regex fallback)", true)
                .withTypeText("AspectJ")
                .withInsertHandler { ctx, _ ->
                    ctx.document.insertString(ctx.tailOffset, "()")
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                }
            prefixed.addElement(PrioritizedLookupElement.withPriority(element, 170.0))
        }

        // Add logical operators
        listOf("&&", "||", "!").forEach { operator ->
            val element = LookupElementBuilder.create(operator)
                .withTailText("  logical operator", true)
                .withTypeText("AspectJ")
            prefixed.addElement(PrioritizedLookupElement.withPriority(element, 120.0))
        }
    }

    private fun collectDeclaredPointcuts(position: PsiElement): List<Pair<String, PointcutDeclaration>> {
        val result = mutableListOf<Pair<String, PointcutDeclaration>>()
        val file = position.containingFile

        // Find all pointcut declarations in the file
        var element: PsiElement? = file.firstChild
        while (element != null) {
            collectPointcutsFromElement(element, result)
            element = element.nextSibling
        }

        return result.distinctBy { it.first }
    }

    private fun collectPointcutsFromElement(
        element: PsiElement,
        result: MutableList<Pair<String, PointcutDeclaration>>
    ) {
        when (element) {
            is AspectDeclaration -> {
                element.getPointcutDeclarations().forEach { pointcut ->
                    pointcut.getPointcutName()?.let { name ->
                        result.add(name to pointcut)
                    }
                }
            }
        }

        // Recursively search children
        var child = element.firstChild
        while (child != null) {
            collectPointcutsFromElement(child, result)
            child = child.nextSibling
        }
    }
}

package org.example.aop.aspectj

import com.intellij.lang.ASTNode
import com.intellij.lang.PsiBuilder
import com.intellij.lang.PsiParser
import com.intellij.psi.tree.IElementType
import org.example.aop.aspectj.psi.AspectJElementTypes

class AspectJParser : PsiParser {
	override fun parse(root: IElementType, builder: PsiBuilder): ASTNode {
		val rootMarker = builder.mark()

		while (!builder.eof()) {
			parseTopLevel(builder)
		}

		rootMarker.done(root)
		return builder.treeBuilt
	}

	private fun parseTopLevel(builder: PsiBuilder) {
		when {
			builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText == "aspect" -> {
				parseAspectDeclaration(builder)
			}
			builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText in setOf("before", "after", "around") -> {
				parseAdviceDeclaration(builder)
			}
			builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText == "pointcut" -> {
				parsePointcutDeclaration(builder)
			}
			builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText == "declare" -> {
				skipDeclaration(builder)
			}
			else -> {
				builder.advanceLexer()
			}
		}
	}

	private fun parseAspectDeclaration(builder: PsiBuilder) {
		val marker = builder.mark()

		// "aspect"
		builder.advanceLexer()

		// aspect name (identifier)
		if (builder.tokenType == AspectJTokenTypes.IDENTIFIER) {
			builder.advanceLexer()
		}

		// skip tokens until we find { or end
		var braceDepth = 0
		while (!builder.eof()) {
			when {
				builder.tokenType?.let { it.toString() == "AJ_PUNCTUATION" } == true && builder.tokenText == "{" -> {
					braceDepth++
					builder.advanceLexer()
					break
				}
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "{" -> {
					braceDepth++
					builder.advanceLexer()
					break
				}
				else -> {
					builder.advanceLexer()
				}
			}
		}

		// parse body
		while (!builder.eof() && braceDepth > 0) {
			when {
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "{" -> {
					braceDepth++
					builder.advanceLexer()
				}
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "}" -> {
					braceDepth--
					if (braceDepth == 0) {
						builder.advanceLexer()
						break
					}
					builder.advanceLexer()
				}
				builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText in setOf("before", "after", "around") -> {
					parseAdviceDeclaration(builder)
				}
				builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText == "pointcut" -> {
					parsePointcutDeclaration(builder)
				}
				else -> {
					builder.advanceLexer()
				}
			}
		}

		marker.done(AspectJElementTypes.ASPECT_DECLARATION)
	}

	private fun parseAdviceDeclaration(builder: PsiBuilder) {
		val marker = builder.mark()

		// advice type: before, after, around
		builder.advanceLexer()

		// (...)
		skipParentheses(builder)

		// optional: returning(...) or throwing(...)
		while (builder.tokenType == AspectJTokenTypes.KEYWORD && builder.tokenText in setOf("returning", "throwing")) {
			builder.advanceLexer()
			skipParentheses(builder)
		}

		// : (colon)
		if (builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == ":") {
			builder.advanceLexer()
		}

		// pointcut expression
		parsePointcutExpression(builder)

		// skip to { or ;
		while (!builder.eof()) {
			when {
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText in setOf("{", ";") -> {
					if (builder.tokenText == "{") {
						skipBraces(builder)
					} else {
						builder.advanceLexer()
					}
					break
				}
				else -> builder.advanceLexer()
			}
		}

		marker.done(AspectJElementTypes.ADVICE_DECLARATION)
	}

	private fun parsePointcutDeclaration(builder: PsiBuilder) {
		val marker = builder.mark()

		// pointcut keyword
		builder.advanceLexer()

		// pointcut name (identifier)
		if (builder.tokenType == AspectJTokenTypes.IDENTIFIER) {
			builder.advanceLexer()
		}

		// (...)
		skipParentheses(builder)

		// : (colon)
		if (builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == ":") {
			builder.advanceLexer()
		}

		// pointcut expression
		parsePointcutExpression(builder)

		// ; or end
		if (builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == ";") {
			builder.advanceLexer()
		}

		marker.done(AspectJElementTypes.POINTCUT_DECLARATION)
	}

	private fun parsePointcutExpression(builder: PsiBuilder) {
		val marker = builder.mark()

		parseDesignatorChain(builder)

		marker.done(AspectJElementTypes.POINTCUT_EXPRESSION)
	}

	private fun parseDesignatorChain(builder: PsiBuilder) {
		while (!builder.eof()) {
			when {
				builder.tokenType == AspectJTokenTypes.KEYWORD &&
					builder.tokenText in setOf("execution", "call", "within", "this", "target", "args", "bean", "if",
										"staticinitialization", "initialization", "preinitialization", "handler",
										"adviceexecution", "cflow", "cflowbelow") -> {
					parseDesignator(builder)
				}
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText in setOf("&&", "||") -> {
					val opMarker = builder.mark()
					builder.advanceLexer()
					opMarker.done(AspectJElementTypes.LOGICAL_OPERATOR)
				}
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "!" -> {
					val opMarker = builder.mark()
					builder.advanceLexer()
					opMarker.done(AspectJElementTypes.LOGICAL_OPERATOR)
				}
				builder.tokenType == AspectJTokenTypes.IDENTIFIER -> {
					// pointcut reference
					val refMarker = builder.mark()
					builder.advanceLexer()
					refMarker.done(AspectJElementTypes.DESIGNATOR_REFERENCE)
				}
				builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText in setOf("(", ")", ";", "{", ":") -> {
					break
				}
				else -> {
					if (builder.tokenType == null) break
					builder.advanceLexer()
				}
			}
		}
	}

	private fun parseDesignator(builder: PsiBuilder) {
		val marker = builder.mark()

		// designator type (e.g., "execution")
		builder.advanceLexer()

		// (...)
		skipParentheses(builder)

		marker.done(AspectJElementTypes.DESIGNATOR)
	}

	private fun skipParentheses(builder: PsiBuilder) {
		if (builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "(") {
			var depth = 0
			while (!builder.eof()) {
				when {
					builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "(" -> {
						depth++
						builder.advanceLexer()
					}
					builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == ")" -> {
						depth--
						builder.advanceLexer()
						if (depth == 0) break
					}
					else -> builder.advanceLexer()
				}
			}
		}
	}

	private fun skipBraces(builder: PsiBuilder) {
		if (builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "{") {
			var depth = 0
			while (!builder.eof()) {
				when {
					builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "{" -> {
						depth++
						builder.advanceLexer()
					}
					builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "}" -> {
						depth--
						builder.advanceLexer()
						if (depth == 0) break
					}
					else -> builder.advanceLexer()
				}
			}
		}
	}

	private fun skipDeclaration(builder: PsiBuilder) {
		// declare warning/error/parents: ...
		while (!builder.eof()) {
			if ((builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == ";") ||
				(builder.tokenType == AspectJTokenTypes.PUNCTUATION && builder.tokenText == "{")) {
				if (builder.tokenText == ";") {
					builder.advanceLexer()
				} else {
					skipBraces(builder)
				}
				break
			}
			builder.advanceLexer()
		}
	}
}

package org.example.aop.aspectj
import com.intellij.lang.ASTNode import com.intellij.lang.PsiParser import com.intellij.lang.ParserDefinition import com.intellij.lexer.Lexer import com.intellij.psi.FileViewProvider import com.intellij.psi.PsiElement import com.intellij.psi.PsiFile import com.intellij.psi.tree.IElementType import com.intellij.psi.tree.TokenSet
class AspectJParserDefinition : ParserDefinition { override fun createLexer(project: com.intellij.openapi.project.Project?): Lexer = AspectJLexer()
override fun createParser(project: com.intellij.openapi.project.Project?): PsiParser = object : PsiParser { override fun parse(root: IElementType, builder: com.intellij.lang.PsiBuilder): ASTNode { val marker = builder.mark() while (!builder.eof()) { builder.advanceLexer() } marker.done(root) return builder.treeBuilt } }
override fun getFileNodeType(): com.intellij.psi.tree.IFileElementType = AspectJTokenTypes.FILE override fun getCommentTokens(): TokenSet = AspectJTokenTypes.COMMENT_TOKENS override fun getStringLiteralElements(): TokenSet = AspectJTokenTypes.STRING_TOKENS override fun createElement(node: ASTNode): PsiElement = com.intellij.extapi.psi.ASTWrapperPsiElement(node) override fun createFile(viewProvider: FileViewProvider): PsiFile = AspectJPsiFile(viewProvider) override fun spaceExistenceTypeBetweenTokens(left: ASTNode?, right: ASTNode?): ParserDefinition.SpaceRequirements = ParserDefinition.SpaceRequirements.MAY }

package org.example.aop.aspectj
import com.intellij.lang.ASTNode import com.intellij.lang.PsiParser import com.intellij.lang.ParserDefinition import com.intellij.lexer.Lexer import com.intellij.psi.FileViewProvider import com.intellij.psi.PsiElement import com.intellij.psi.PsiFile import com.intellij.psi.tree.IElementType import com.intellij.psi.tree.TokenSet import org.example.aop.aspectj.psi.*
class AspectJParserDefinition : ParserDefinition { override fun createLexer(project: com.intellij.openapi.project.Project?): Lexer = AspectJLexer()
override fun createParser(project: com.intellij.openapi.project.Project?): PsiParser = AspectJParser()
override fun getFileNodeType(): com.intellij.psi.tree.IFileElementType = AspectJTokenTypes.FILE override fun getCommentTokens(): TokenSet = AspectJTokenTypes.COMMENT_TOKENS override fun getStringLiteralElements(): TokenSet = AspectJTokenTypes.STRING_TOKENS
override fun createElement(node: ASTNode): PsiElement { return when (node.elementType) { AspectJElementTypes.ASPECT_DECLARATION -> AspectDeclaration(node) AspectJElementTypes.ADVICE_DECLARATION -> AdviceDeclaration(node) AspectJElementTypes.POINTCUT_DECLARATION -> PointcutDeclaration(node) AspectJElementTypes.POINTCUT_EXPRESSION -> PointcutExpression(node) AspectJElementTypes.DESIGNATOR -> Designator(node) AspectJElementTypes.DESIGNATOR_REFERENCE -> DesignatorReference(node) else -> com.intellij.extapi.psi.ASTWrapperPsiElement(node) } }
override fun createFile(viewProvider: FileViewProvider): PsiFile = AspectJPsiFile(viewProvider) override fun spaceExistenceTypeBetweenTokens(left: ASTNode?, right: ASTNode?): ParserDefinition.SpaceRequirements = ParserDefinition.SpaceRequirements.MAY }

@file:Suppress("unused")

package org.example.aop.aspectj.psi

import com.intellij.psi.tree.IElementType
import org.example.aop.aspectj.AspectJLanguage

object AspectJElementTypes {
	// File-level elements
	val ASPECT_DECLARATION = IElementType("AJ_ASPECT_DECLARATION", AspectJLanguage)

	// Advice and Pointcuts
	val ADVICE_DECLARATION = IElementType("AJ_ADVICE_DECLARATION", AspectJLanguage)
	val POINTCUT_DECLARATION = IElementType("AJ_POINTCUT_DECLARATION", AspectJLanguage)

	// Pointcut expression parts
	val POINTCUT_EXPRESSION = IElementType("AJ_POINTCUT_EXPRESSION", AspectJLanguage)
	val DESIGNATOR = IElementType("AJ_DESIGNATOR", AspectJLanguage)
	val DESIGNATOR_TYPE = IElementType("AJ_DESIGNATOR_TYPE", AspectJLanguage)
	val DESIGNATOR_CONTENT = IElementType("AJ_DESIGNATOR_CONTENT", AspectJLanguage)
	val DESIGNATOR_REFERENCE = IElementType("AJ_DESIGNATOR_REFERENCE", AspectJLanguage)

	// Operators
	val LOGICAL_OPERATOR = IElementType("AJ_LOGICAL_OPERATOR", AspectJLanguage)

	// Advice metadata
	val ADVICE_TYPE = IElementType("AJ_ADVICE_TYPE", AspectJLanguage)
	val RETURNING = IElementType("AJ_RETURNING", AspectJLanguage)
	val THROWING = IElementType("AJ_THROWING", AspectJLanguage)
	val PARAMETERS = IElementType("AJ_PARAMETERS", AspectJLanguage)

	// Modifiers and identifiers
	val MODIFIER = IElementType("AJ_MODIFIER", AspectJLanguage)

	// Forward compatibility
	val IDENTIFIER = IElementType("AJ_IDENTIFIER", AspectJLanguage)
}

@file:Suppress("unused")

package org.example.aop.aspectj.psi

import com.intellij.extapi.psi.ASTWrapperPsiElement
import com.intellij.lang.ASTNode
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiNameIdentifierOwner
import com.intellij.psi.util.PsiTreeUtil

// ============================================================================
// Base PSI Elements
// ============================================================================

abstract class AspectJPsiElement(node: ASTNode) : ASTWrapperPsiElement(node)

// ============================================================================
// File-level Elements
// ============================================================================

class AspectDeclaration(node: ASTNode) : AspectJPsiElement(node) {
	fun getAspectName(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType?.toString()?.contains("IDENTIFIER") == true) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}

	fun getAdviceDeclarations(): List<AdviceDeclaration> =
		PsiTreeUtil.getChildrenOfTypeAsList(this, AdviceDeclaration::class.java)

	fun getPointcutDeclarations(): List<PointcutDeclaration> =
		PsiTreeUtil.getChildrenOfTypeAsList(this, PointcutDeclaration::class.java)
}

// ============================================================================
// Advice Elements
// ============================================================================

class AdviceDeclaration(node: ASTNode) : AspectJPsiElement(node) {
	fun getAdviceType(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.ADVICE_TYPE) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}

	fun getPointcutExpression(): PointcutExpression? =
		PsiTreeUtil.findChildOfType(this, PointcutExpression::class.java)

	fun getParameters(): PsiElement? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.PARAMETERS) {
				return child
			}
			child = child.nextSibling
		}
		return null
	}

	fun getReturningType(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.RETURNING) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}

	fun getThrowingType(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.THROWING) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}
}

// ============================================================================
// Pointcut Elements
// ============================================================================

class PointcutDeclaration(node: ASTNode) : AspectJPsiElement(node), PsiNameIdentifierOwner {
	fun getPointcutName(): String? = nameIdentifier?.text

	override fun getNameIdentifier(): PsiElement? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType?.toString()?.contains("IDENTIFIER") == true) {
				return child
			}
			child = child.nextSibling
		}
		return null
	}

	override fun getName(): String? = nameIdentifier?.text

	override fun setName(name: String): PsiElement = throw UnsupportedOperationException()

	fun getModifier(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.MODIFIER) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}

	fun getParameters(): PsiElement? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.PARAMETERS) {
				return child
			}
			child = child.nextSibling
		}
		return null
	}

	fun getPointcutExpression(): PointcutExpression? =
		PsiTreeUtil.findChildOfType(this, PointcutExpression::class.java)
}

class PointcutExpression(node: ASTNode) : AspectJPsiElement(node) {
	fun getDesignators(): List<Designator> =
		PsiTreeUtil.getChildrenOfTypeAsList(this, Designator::class.java)

	fun getLogicalOperators(): List<PsiElement> =
		PsiTreeUtil.getChildrenOfTypeAsList(this, PsiElement::class.java)
			.filter { it.node?.elementType == AspectJElementTypes.LOGICAL_OPERATOR }
}

class Designator(node: ASTNode) : AspectJPsiElement(node) {
	fun getDesignatorType(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.DESIGNATOR_TYPE) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}

	fun getDesignatorContent(): String? {
		var child = firstChild
		while (child != null) {
			if (child.node?.elementType == AspectJElementTypes.DESIGNATOR_CONTENT) {
				return child.text
			}
			child = child.nextSibling
		}
		return null
	}
}

// ============================================================================
// Supporting Elements
// ============================================================================

class DesignatorReference(node: ASTNode) : AspectJPsiElement(node) {
	val referenceName: String? get() = text
}
